// JÙLABA ACADEMY - Questions du jeu (style Duolingo)
// Structure: role → chapitre (1-3) → questions (5 par leçon × 5 leçons = 25/chapitre)
// Chaque leçon d'un chapitre pioche dans le pool du chapitre (5 questions distinctes par leçon)

import { UserRole } from './types';

export interface AcademyQuestion {
  id: string;
  role: UserRole;
  chapter: number;       // 1, 2 ou 3
  lesson: number;        // 1 à 5 (numéro de leçon dans le chapitre)
  question: string;      // Max 10 mots, simple et ivoirien
  options: { text: string; icon: string }[]; // 4 choix avec icône lucide
  correctIndex: number;  // Index de la bonne réponse (0-3)
  explanation: string;   // Explication courte après réponse
  active: boolean;       // Peut être désactivé depuis le BackOffice
}

