// ─────────────────────────────────────────────────────────────────────────────
// ASSEMBLER TOUTES LES QUESTIONS
// ─────────────────────────────────────────────────────────────────────────────
function buildQuestions(
  rawList: Omit<AcademyQuestion, 'id' | 'role' | 'active'>[],
  role: UserRole
): AcademyQuestion[] {
  return rawList.map((q, i) => ({
    ...q,
    id: `${role}-ch${q.chapter}-l${q.lesson}-q${i}`,
    role,
    active: true,
  }));
}

export const ALL_ACADEMY_QUESTIONS: AcademyQuestion[] = [
  ...buildQuestions(MARCHAND_QUESTIONS, 'marchand'),
  ...buildQuestions(PRODUCTEUR_QUESTIONS, 'producteur'),
  ...buildQuestions(COOPERATIVE_QUESTIONS, 'cooperative'),
  ...buildQuestions(IDENTIFICATEUR_QUESTIONS, 'identificateur'),
  ...buildQuestions(INSTITUTION_QUESTIONS, 'institution'),
];

export function getQuestionsForLesson(
  role: UserRole,
  chapter: number,
  lesson: number
): AcademyQuestion[] {
  return ALL_ACADEMY_QUESTIONS.filter(
    q => q.role === role && q.chapter === chapter && q.lesson === lesson && q.active
  );
}

export function getQuestionsForChapter(role: UserRole, chapter: number): AcademyQuestion[] {
  const stored = localStorage.getItem(`julaba-academy-questions-${role}-${chapter}`);
  if (stored) {
    try {
      const parsed: AcademyQuestion[] = JSON.parse(stored);
      if (parsed.length > 0) return parsed.filter(q => q.active);
    } catch { /* ignore */ }
  }
  return ALL_ACADEMY_QUESTIONS.filter(
    q => q.role === role && q.chapter === chapter && q.active
  );
}

// Alias for backwards-compat with BOAcademy imports
export const ACADEMY_QUESTIONS = ALL_ACADEMY_QUESTIONS;

// Récupérer toutes les questions d'un rôle (tous chapitres, depuis localStorage si modifiées)
export function getAllQuestionsForRole(role: UserRole): AcademyQuestion[] {
  const result: AcademyQuestion[] = [];
  for (let ch = 1; ch <= 3; ch++) {
    const stored = localStorage.getItem(`julaba-academy-questions-${role}-${ch}`);
    if (stored) {
      try {
        const parsed: AcademyQuestion[] = JSON.parse(stored);
        if (parsed.length > 0) { result.push(...parsed); continue; }
      } catch { /* ignore */ }
    }
    result.push(...ALL_ACADEMY_QUESTIONS.filter(q => q.role === role && q.chapter === ch));
  }
  return result;
}

// Sauvegarder les questions modifiées par le BackOffice
export function saveAllQuestionsForRole(role: UserRole, questions: AcademyQuestion[]): void {
  for (let ch = 1; ch <= 3; ch++) {
    const chapterQs = questions.filter(q => q.chapter === ch);
    localStorage.setItem(`julaba-academy-questions-${role}-${ch}`, JSON.stringify(chapterQs));
  }
}
